import { observable } from "mobx";

export class Store {
  @observable menu: string = "none";
  @observable tab_menu_welcome: string = "lg";

  chooseTabMenuWelcome(tab: string) {
    console.log(`before: $(this.tab_menu_welcome)`);
    this.tab_menu_welcome = tab;
    console.log(`after: ${this.tab_menu_welcome}`);
  }
}
